use std::marker::PhantomPinned;

struct MemoryHolder<T> {
    phantom: PhantomPinned,
    value: Option<T>,
}

impl<T: std::fmt::Debug + 'static> MemoryHolder<T> {
    fn new(val: T) -> Self {
        MemoryHolder { 
            phantom: PhantomPinned,
            value: Some(val)
        }
    }

    fn get_value(&self) -> Option<&T> {
        self.value.as_ref()
    }
}

fn main() {
    let original_data = 42;
    let holder: MemoryHolder<i32> = MemoryHolder::new(original_data);

    match holder.get_value() {
        Some(val) => println!("Successfully accessed pinned value: {}", val),
        None => println!("Failed to access the stored value."),
    }
}

use std::mem;
use std::marker::PhantomPinned;

struct SelfReferential { 
    data: u32,
    ptr: *const u32,
    _phantom: PhantomPinned,
}

impl SelfReferential {
    fn new(value: u32) -> Self {
        let mut s = SelfReferential { 
            data: value, 
            ptr: std::ptr::null(), 
            _phantom: PhantomPinned,
        };
        // In a real scenario, the pointer would be set relative to 's' itself.
        // Here we just demonstrate construction and pinning concept.
        s.ptr = &value as *const u32;
        s
    }

    fn use_pinned(&self) -> u32 {
        // Accessing the pointer demonstrates that it is conceptually stable/pinned.
        unsafe { *self.ptr }
    }
}

fn main() {
    let s = SelfReferential::new(42);
    println!("Value read via pinned field: {}", s.use_pinned());
}

