impl SelfReferential {
    fn new(initial_value: u32) -> Self {
        let mut s = SelfReferential { 
            data: std::ptr::null(), 
            value: initial_value 
        };
        // Simulate pinning by ensuring data points to something relative
        s.data = &s.value as *const u32;
        s
    }

    fn print_info(&self) {
        println!("Value: {}", self.value);
        unsafe {
            if !self.data.is_null() {
                println!("Pinned Data Address (from value): {:?}", self.data);
            }
        }
    }
}

