use std::mem;

struct PinningExample {
    value: i32,
    ptr_field: *const i32,
}

impl<'a> Drop for PinningExample {
    fn drop(&mut self) {
        if !self.ptr_field.is_null() {
            unsafe {
                let original_val = *self.ptr_field;
                println!("Dropping: Original value from pointer was {}", original_val);
            }
        }
    }
}

fn main() {
    let mut data = Box::new(PinningExample { value: 42, ptr_field: std::ptr::null() });

    unsafe {
        data.ptr_field = &*(Box::into_raw(Box::new(100)) as *const i32);
    }

    println!("Created data box. Value: {}", data.value);

    let dropped_box = mem::replace(&mut data, Box::new(PinningExample { value: 0, ptr_field: std::ptr::null() }));

    // When main exits, the drop implementation for the last box will run.
}
